  ('medical-tech-moex-00299', 'medical-tech', 'medical-tech-moex-112-0356504f', 'sub-medical-tech-04', NULL, 'single_choice', '流感病毒（Influenza virus）是一種RNA病毒，每年都會造成流行，故須接種疫苗來進行預防。下列敘述何者 正確？', '["A型流感病毒有可能會感染禽鳥類", "B型流感病毒於1918年造成西班牙2千多萬人死亡", "C型流感病毒不會傳染人類", "流感病毒的典型症狀多樣，但不包括結膜炎"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:29+00:00", "source_pdf_sha1": "6ded8338776e", "answer_pdf_sha1": "de093d821ec4", "source_family": "moex-gov-tw", "moex": {"exam_code": "112020", "c": "308", "s": "66", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "臨床血清免疫學與臨床病毒學", "year": "112", "exam_name": "112年第一次專技人員高等考試醫師牙醫師中醫師藥師考試分階段考試、醫事檢驗師、醫事放射師、物理治療師考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "slug": "mt", "db_exam_id": "medical-tech"}'::jsonb, NULL),
